     **/
    getMessage() {
      alert("getMessage");
      //mam.navigator.loadconfig.messageInfo('1', getMsgCallback);
      mam.navigator.loadconfig.messageInfo("1", this.getMsgCallback);
    },
    getMsgCallback(obj) {
      alert(obj);
      alert(
        "消息标题：" +
          obj.messageheader +
