      //alert("加载本地数据库数据");
      var array = [];
      var DbName = "";
      var tableName = "";
      //获取设备平台
      var devicePlatform = device.platform;
      console.log(" executeOpenFile() ,devicePlatform:" + devicePlatform);
      if ("iOS" == devicePlatform) {
        /**  IOS使用**/
        DbName = "IMDB.sqlite";
        tableName = "T_DB_SERVER_CODE";
      } else if ("Android" == devicePlatform) {
        /**  安卓使用**/
        DbName = "dlxx_mam.db";
        tableName = "accounts";
      } else {
