      array.push(null);
      array.push(null);
      array.push(null);
      array.push(null);
      array.push(null);

      mam.navigator.SQLiteCordovaPlugin.queryDate(
        DbName,
        tableName,
        successFunction,
        errorFunction
      );
    },

    successFunction(v) {
      alert("OKEY111");
      alert(v);
      alert(JSON.stringify(v));
